practice_tasks.solution:
class BaseRequest:
    def __init__(self, url):
        self.url = url

class SecureRequest(BaseRequest):
    def __init__(self, url, token):
        super().__init__(url)
        self.token = token

code_walkthrough.code:
class Worker:
    def start(self):
        print('worker started')

class CeleryWorker(Worker):
    def start(self):
        super().start()
        print('connected to broker')

w = CeleryWorker()
w.start()

